#nullable enable // autogenerated  

using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2.Vanilla.Shells;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Projectiles
{
    [EntityBehaviourDefinition(VanillaProjectileNames.PurpleKnife)]
    public class PurpleKnife : ProjectileBehaviour
    {
        public PurpleKnife(string nsp, string name) : base(nsp, name)
        {
        }

        protected override void PostHitEntity(ProjectileHitOutput hitResult, DamageOutput? damageOutput)
        {
            base.PostHitEntity(hitResult, damageOutput);

            // ﾗﾏﾉｫｷﾉｵｶﾎﾞﾏﾞｴｩﾍｸ  
            hitResult.Pierce = true;
        }
    }
}